                        backdrop-blur-sm
                    `})}catch(o){console.error("Error:",o),Swal.fire({icon:"error",title:"Koneksi Terputus",text:"Tidak dapat menghubungi server sistem. Silakan coba beberapa saat lagi.",confirmButtonText:"Tutup",buttonsStyling:!1,customClass:{popup:"rounded-3xl shadow-2xl border border-gray-100",title:"font-outfit font-bold text-gray-900",htmlContainer:"font-outfit text-gray-500",confirmButton:"bg-gray-800 hover:bg-gray-900 text-white font-semibold py-3 px-6 rounded-xl transition-colors font-outfit"},backdrop:`
